// Extrai dados do payload enviado pelo Flowz
const body = $input.first().json.body || $input.first().json;

const empresaId      = body.empresaId;
const instanceName   = body.instanceName;
const remetente      = body.remetente;       // JID: 5511999@s.whatsapp.net
const nomeRemetente  = body.nomeRemetente || 'Cliente';
const mensagem       = body.mensagem;
const historico      = body.historico || []; // [{papel, conteudo}]
const mediaBase64    = body.mediaBase64 || null;
const mediaType      = body.mediaType || 'texto'; // texto|imagem|audio

return [{
  json: {
    empresaId,
    instanceName,
    remetente,
    nomeRemetente,
    mensagem,
    historico,
    mediaBase64,
    mediaType,
    telefone: remetente.replace('@s.whatsapp.net', '').replace(/\D/g, ''),
  }
}];

// Verifica se cliente pediu para falar com humano
const config    = $('Buscar Config do Agente').first().json;
const dados     = $('Extrair Dados').first().json;
const mensagem  = (dados.mensagem || '').toLowerCase();
const gatilho   = (config.transferir_humano || 'atendente').toLowerCase();

const querHumano = mensagem.includes(gatilho);

// Verifica horário de atendimento
const agora = new Date();
const horaAtual = agora.getHours() * 60 + agora.getMinutes();
const diasSemana = config.dias_semana || [1,2,3,4,5];
const diaAtual = agora.getDay();

const [hInicio, mInicio] = (config.horario_inicio || '08:00').split(':').map(Number);
const [hFim, mFim]       = (config.horario_fim || '18:00').split(':').map(Number);
const inicioMin = hInicio * 60 + mInicio;
const fimMin    = hFim * 60 + mFim;

const dentroHorario = diasSemana.includes(diaAtual) && horaAtual >= inicioMin && horaAtual < fimMin;

return [{
  json: {
    ...dados,
    config,
    querHumano,
    dentroHorario,
    mensagemForaHora: config.mensagem_fora_hora || 'Olá! Estamos fora do horário de atendimento.',
  }
}];

// Monta o system prompt com todas as informações da empresa
const ctx    = $('Verificar Contexto').first().json;
const config = ctx.config;
const horariosData = $('Buscar Horários Disponíveis').first().json;
const slots = (horariosData.slots || []).slice(0, 8); // máx 8 slots

const slotsTexto = slots.length > 0
  ? slots.map(s => `- ${s.label}`).join('\n')
  : 'Nenhum horário disponível no momento.';

// Histórico formatado
const historicoTexto = ctx.historico.map(h => 
  `${h.papel === 'usuario' ? ctx.nomeRemetente : config.nome}: ${h.conteudo}`
).join('\n');

const systemPrompt = `Você é ${config.nome || 'um assistente'}, atendente virtual da empresa ${config.nome_empresa || 'nossa empresa'}.

SEGMENTO: ${config.segmento || 'Não informado'}
TOM DE VOZ: ${config.tom_voz || 'neutro'}

SOBRE A EMPRESA:
${config.sobre_empresa || 'Empresa focada em atendimento de qualidade.'}

SERVIÇOS E PRODUTOS:
${config.servicos || 'Consulte nossos serviços.'}

INSTRUÇÕES ADICIONAIS:
${config.prompt_sistema || ''}

HORÁRIOS DISPONÍVEIS PARA AGENDAMENTO:
${slotsTexto}

RETORNO ESPERADO:
Responda SEMPRE em JSON com este formato:
{
  "resposta": "sua resposta para o cliente",
  "acao": "nenhuma" | "criar_lead" | "agendar",
  "lead_titulo": "título do lead se acao=criar_lead",
  "agendamento_slot": "dataHora ISO se acao=agendar",
  "ignorar": false
}

Se o cliente demonstrar interesse em comprar/contratar, use acao=criar_lead.
Se o cliente quiser agendar, use acao=agendar e coloque o slot escolhido.
Se for apenas bate-papo, use acao=nenhuma.
Nunca saia do formato JSON.`;

return [{
  json: {
    ...ctx,
    systemPrompt,
    slots,
  }
}];

