// Extrai e parseia a resposta do OpenAI
const oaiResponse = $input.first().json;
const ctx = $('Montar Prompt').first().json;

let resposta = null;
try {
  const content = oaiResponse.choices?.[0]?.message?.content || '{}';
  resposta = JSON.parse(content);
} catch(e) {
  resposta = { resposta: 'Desculpe, tive um problema. Tente novamente!', acao: 'nenhuma', ignorar: false };
}

return [{
  json: {
    ...ctx,
    respostaIA: resposta,
    textoResposta: resposta.resposta || '',
    acao: resposta.acao || 'nenhuma',
    ignorar: resposta.ignorar || false,
    leadTitulo: resposta.lead_titulo || `Lead - ${ctx.nomeRemetente}`,
    agendamentoSlot: resposta.agendamento_slot || null,
  }
}];
